import{d as e,l as t,o as n,t as r,x as i}from"./_plugin-vue_export-helper-BNz78J85.js";var a={},o={class:`policyPage`};function s(r,a){return i(),t(`div`,o,[n(`button`,{class:`back`,onClick:a[0]||=e=>r.$router.back()},`← 返回`),a[1]||=e(`<h1 data-v-91806f26>平台售后说明</h1><p class="updateDate" data-v-91806f26>更新日期：2026年6月</p><section data-v-91806f26><h2 data-v-91806f26>一、基础原则</h2><p data-v-91806f26>Second hand 是一个C2C二手交易信息撮合平台，平台本身不持有商品、不介入物流、不对商品质量兜底。买卖双方通过平台达成交易，交易风险由双方自行评估和承担。</p><ul data-v-91806f26><li data-v-91806f26><strong data-v-91806f26>优先级：</strong>商品详情页约定 + 站内聊天约定 &gt; 平台通用规则。仅平台站内聊天记录有效，微信/QQ/线下口头约定平台不予采信。</li><li data-v-91806f26><strong data-v-91806f26>平台角色：</strong>平台仅提供信息展示、交易撮合、纠纷仲裁服务，不对商品真伪、质量、物流时效做任何保证。</li></ul></section><section data-v-91806f26><h2 data-v-91806f26>二、责任判定</h2><table data-v-91806f26><thead data-v-91806f26><tr data-v-91806f26><th data-v-91806f26>场景</th><th data-v-91806f26>责任方</th><th data-v-91806f26>处理方式</th></tr></thead><tbody data-v-91806f26><tr data-v-91806f26><td data-v-91806f26>货不对板、隐瞒暗病、假货</td><td data-v-91806f26>卖家</td><td data-v-91806f26>卖家承担往返运费，支持退货/仅退款</td></tr><tr data-v-91806f26><td data-v-91806f26>发错货、发货破损</td><td data-v-91806f26>卖家</td><td data-v-91806f26>卖家承担往返运费，支持退货/仅退款</td></tr><tr data-v-91806f26><td data-v-91806f26>人为损坏、主观不想要</td><td data-v-91806f26>买家</td><td data-v-91806f26>无约定则驳回售后；退货买家自理运费</td></tr><tr data-v-91806f26><td data-v-91806f26>物流破损（签收前拒收）</td><td data-v-91806f26>卖家</td><td data-v-91806f26>卖家全责，支持全额退款</td></tr><tr data-v-91806f26><td data-v-91806f26>物流破损（签收后发现）</td><td data-v-91806f26>谁举证谁追责</td><td data-v-91806f26>需提供签收时开箱证据</td></tr></tbody></table></section><section data-v-91806f26><h2 data-v-91806f26>三、售后时效红线</h2><ul data-v-91806f26><li data-v-91806f26><strong data-v-91806f26>未确认收货：</strong>全周期可发起售后，无时间限制。</li><li data-v-91806f26><strong data-v-91806f26>确认收货后：</strong>15个自然天内为售后窗口期。超15天系统自动关闭售后入口，平台不再受理任何维权申请，订单资金彻底清算完结。</li></ul></section><section data-v-91806f26><h2 data-v-91806f26>四、售后类型及流程</h2><h3 data-v-91806f26>4.1 仅退款（未发货/未签收，无需退货）</h3><ol data-v-91806f26><li data-v-91806f26>买家提交仅退款申请</li><li data-v-91806f26>卖家72小时（3自然天）内处理： <ul data-v-91806f26><li data-v-91806f26><strong data-v-91806f26>同意：</strong>原路全额退款，售后闭环，订单关闭。</li><li data-v-91806f26><strong data-v-91806f26>拒绝：</strong>买家3天内可选&quot;平台介入&quot;；超3天不操作则售后关闭，订单继续履约。</li><li data-v-91806f26><strong data-v-91806f26>超时未处理：</strong>系统自动全额退款，售后完结。</li></ul></li></ol><h3 data-v-91806f26>4.2 仅退款（已收到货、不退回商品）</h3><p data-v-91806f26>平台不会自动同意此类仅退款。仅在以下场景生效：</p><ul data-v-91806f26><li data-v-91806f26>买卖双方协商一致，卖家手动同意退款；</li><li data-v-91806f26>平台仲裁判定假货/全损无法退回，裁定仅退款。</li></ul><p data-v-91806f26>卖家超时不处理<strong data-v-91806f26>不会</strong>自动退款。买家申请→卖家72h审核→同意则退款；拒绝则买家可申请平台介入。</p><h3 data-v-91806f26>4.3 退货退款（核心链路，四段超时）</h3><div class="flowBox" data-v-91806f26><div class="flowStep" data-v-91806f26><strong data-v-91806f26>阶段1：</strong>买家提交退货退款 → 卖家72h审核<br data-v-91806f26> 同意→进入待寄件；拒绝→买家3天介入，超时关闭<br data-v-91806f26> 卖家72h未处理→系统自动同意退货，进入待寄件</div><div class="flowStep" data-v-91806f26><strong data-v-91806f26>阶段2：</strong>待买家寄件 → 买家7自然天内填写退货单号<br data-v-91806f26> 7天内填单号→进入待签收；超7天未填→售后关闭，订单正常打款</div><div class="flowStep" data-v-91806f26><strong data-v-91806f26>阶段3：</strong>已填退货单号 → 卖家10自然天内确认收货<br data-v-91806f26> 卖家确认无误→退款原路返还；卖家拒收→买家可申请平台介入<br data-v-91806f26> 超10天未确认→系统默认签收无误，自动退款</div><div class="flowStep" data-v-91806f26><strong data-v-91806f26>阶段4：</strong>退款完成，售后闭环</div></div><h3 data-v-91806f26>4.4 部分退款（商品自留、折价补偿）</h3><p data-v-91806f26>无强制超时机制。双方协商金额，卖家同意即部分退款完结；卖家拒绝则买家可走平台仲裁裁定折价金额。</p></section><section data-v-91806f26><h2 data-v-91806f26>五、平台介入（仲裁）</h2><ol data-v-91806f26><li data-v-91806f26><strong data-v-91806f26>触发条件：</strong>卖家拒绝售后 → 买家点击&quot;申请平台介入&quot;。</li><li data-v-91806f26><strong data-v-91806f26>举证规则——谁主张谁举证：</strong><ul data-v-91806f26><li data-v-91806f26>买家主张货不对板：需提供完整带时间戳开箱视频（含快递面单+未拆封外包装+实物）、商品详情截图、站内聊天记录。缺核心开箱视频大概率败诉。</li><li data-v-91806f26>卖家主张买家人为损坏：需提供发货打包全流程视频、收货拆包验货视频。无法举证则判卖家败诉。</li></ul></li><li data-v-91806f26><strong data-v-91806f26>仲裁三结果：</strong><ul data-v-91806f26><li data-v-91806f26>全额退款（退货退款或仅退款）</li><li data-v-91806f26>部分折价退款</li><li data-v-91806f26>驳回售后申请</li></ul> 裁决为平台最终结果，不可二次申诉。 </li><li data-v-91806f26><strong data-v-91806f26>审核时效：</strong>平台3~5个工作日出具裁决结果。</li></ol></section><section data-v-91806f26><h2 data-v-91806f26>六、免责声明</h2><p data-v-91806f26>Second hand 作为信息撮合平台，对于以下情形不承担责任：</p><ul data-v-91806f26><li data-v-91806f26>商品真伪、质量、功能完好性等实质问题；</li><li data-v-91806f26>买卖双方通过非平台渠道（微信、QQ、线下等）进行的沟通和约定；</li><li data-v-91806f26>物流运输过程中产生的延误、损毁、丢失（由物流公司承担责任）；</li><li data-v-91806f26>因不可抗力导致的交易无法履行。</li></ul><p data-v-91806f26>平台鼓励买卖双方在交易前充分沟通，保留站内聊天记录作为后续维权依据。</p></section>`,8)])}var c=r(a,[[`render`,s],[`__scopeId`,`data-v-91806f26`]]);export{c as default};